<?php $page_title='Chi tiết đơn';require __DIR__.'/_layout_start.php';require_once __DIR__.'/../models/Order.php';$pdo=db_connect();$id=(int)($_GET['id']??0);$order=$pdo->prepare("SELECT dh.*,nd.ho_ten,nd.email,pt.ten_phuong_thuc FROM don_hang dh JOIN nguoi_dung nd ON nd.id_nguoi_dung=dh.id_nguoi_dung LEFT JOIN phuong_thuc_thanh_toan pt ON pt.id_phuong_thuc=dh.id_phuong_thuc WHERE id_don_hang=:id");$order->execute([':id'=>$id]);$o=$order->fetch();$items=(new Order($pdo))->getItems($id);?><h1>Đơn #<?=$id?></h1><div class="bg-white p-4 rounded-4"><p>Khách: <?=h($o['ho_ten'])?> - <?=h($o['email'])?></p><p>Nhận hàng: <?=h($o['ten_nguoi_nhan'])?>, <?=h($o['so_dien_thoai_nhan'])?>, <?=h($o['dia_chi_giao_hang'])?></p><table class="table"><?php foreach($items as $it):?><tr><td><?=h($it['ten_san_pham'])?></td><td><?=$it['so_luong']?></td><td><?=format_price($it['thanh_tien'])?></td></tr><?php endforeach;?></table></div><?php require __DIR__.'/_layout_end.php';?>
